#include <bits/stdc++.h>
using namespace std;
const int maxn=1e4+6e3+5;
int n,dp[maxn][5],c[maxn],vis[maxn];
vector<int> g[maxn];
void dfs(int u) {
	vis[u]=1;
	dp[u][1]=1;
	dp[u][2]=2;
	dp[u][3]=3;
	dp[u][4]=4;
	for(auto v:g[u]) {
		if(!vis[v]){
			dfs(v);
			dp[u][1]+=min({dp[v][2],dp[v][3],dp[v][4]});
			dp[u][2]+=min({dp[v][1],dp[v][3],dp[v][4]});
			dp[u][3]+=min({dp[v][2],dp[v][1],dp[v][4]});
			dp[u][4]+=min({dp[v][1],dp[v][2],dp[v][3]});
		}
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	if(n==1){
		cout<<n;
		return 0;
	}
	for(int i=1; i<n; i++) {
		int a,b;
		cin>>a>>b;
		g[a].emplace_back(b);
		g[b].emplace_back(a);
	}
	dfs(1);
	cout<<min({dp[1][1],dp[1][2],dp[1][3],dp[1][4]});
	return 0;
}
